#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeSessionOrchestrator: FfiConverter {
    typealias FfiType = UInt64
    typealias SwiftType = SessionOrchestrator

    public static func lift(_ handle: UInt64) throws -> SessionOrchestrator {
        return SessionOrchestrator(unsafeFromHandle: handle)
    }

    public static func lower(_ value: SessionOrchestrator) -> UInt64 {
        return value.uniffiCloneHandle()
    }

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> SessionOrchestrator {
        let handle: UInt64 = try readInt(&buf)
        return try lift(handle)
    }

    public static func write(_ value: SessionOrchestrator, into buf: inout [UInt8]) {
        writeInt(&buf, lower(value))
    }
}


#if swift(>=5.8)
@_documentation(visibility: private)
