public enum ConnectionPublicState: Equatable, Hashable {
    
    case disconnected(reason: String?, issueHint: ConnectionIssueHint?
    )
    case connecting
    case connected(host: String
    )
    case error(message: String
    )
    /**
     * ńŞÇň║Ž`Connected`ŃüźŃü¬ŃüúŃüčŃé╗ŃââŃéĚŃâžŃâ│Ńüîń║łŠťčŃüŤŃüÜňłçŠľşŃüĽŃéîŃüčÚÜŤŃÇüorchestratorŃüî
     * Ŕç¬ňőĽšÜäŃüźňćŹŠÄąšÂÜŃéĺŔęŽŃü┐ŃüŽŃüäŃéőÚľôŃü«šŐÂŠůő(`orchestrator.rs`Ńü«reconnectŃâźŃâ╝ŃâŚňĆéšůž)ŃÇé
     * `elapsed_secs`/`timeout_secs`Ńü»UIŃüîŃâęŃéĄŃâľŃü¬ŃéźŃéŽŃâ│ŃâłŃâÇŃéŽŃâ│ŃéĺŠĆĆšö╗ŃüÖŃéőŃüčŃéüŃü«
     * SSOTňÇĄ(Kotlinňü┤ŃüžŃé┐ŃéĄŃâ×Ńâ╝ŃéĺŠîüŃüčŃü¬Ńüä)ŃÇé
     */
    case reconnecting(elapsedSecs: UInt32, timeoutSecs: UInt32, reason: String?
    )





}

#if compiler(>=6)
extension ConnectionPublicState: Sendable {}
#endif

#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeConnectionPublicState: FfiConverterRustBuffer {
    typealias SwiftType = ConnectionPublicState

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> ConnectionPublicState {
        let variant: Int32 = try readInt(&buf)
        switch variant {
        
        case 1: return .disconnected(reason: try FfiConverterOptionString.read(from: &buf), issueHint: try FfiConverterOptionTypeConnectionIssueHint.read(from: &buf)
        )
        
        case 2: return .connecting
        
        case 3: return .connected(host: try FfiConverterString.read(from: &buf)
        )
        
        case 4: return .error(message: try FfiConverterString.read(from: &buf)
        )
        
        case 5: return .reconnecting(elapsedSecs: try FfiConverterUInt32.read(from: &buf), timeoutSecs: try FfiConverterUInt32.read(from: &buf), reason: try FfiConverterOptionString.read(from: &buf)
        )
        
        default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: ConnectionPublicState, into buf: inout [UInt8]) {
        switch value {
        
        
        case let .disconnected(reason,issueHint):
            writeInt(&buf, Int32(1))
            FfiConverterOptionString.write(reason, into: &buf)
            FfiConverterOptionTypeConnectionIssueHint.write(issueHint, into: &buf)
            
        
        case .connecting:
            writeInt(&buf, Int32(2))
        
        
        case let .connected(host):
            writeInt(&buf, Int32(3))
            FfiConverterString.write(host, into: &buf)
            
        
        case let .error(message):
            writeInt(&buf, Int32(4))
            FfiConverterString.write(message, into: &buf)
            
        
        case let .reconnecting(elapsedSecs,timeoutSecs,reason):
            writeInt(&buf, Int32(5))
            FfiConverterUInt32.write(elapsedSecs, into: &buf)
            FfiConverterUInt32.write(timeoutSecs, into: &buf)
            FfiConverterOptionString.write(reason, into: &buf)
            
        }
    }
}


